/// <param name="product">Product</param>
/// <param name="excludeProperties">Whether to exclude populating of some properties of model</param>
/// <returns>
/// A task that represents the asynchronous operation
/// The task result contains the product model
/// </returns>
public virtual async Task<ProductModel> PrepareProductModelAsync(ProductModel model, Product product, bool excludeProperties = false)
{
    Func<ProductLocalizedModel, int, Task> localizedModelConfiguration = null;

    if (product != null)
    {
        //fill in model values from the entity
        if (model == null)
        {
            model = product.ToModel<ProductModel>();
            model.SeName = await _urlRecordService.GetSeNameAsync(product, 0, true, false);
        }

        var parentGroupedProduct = await _productService.GetProductByIdAsync(product.ParentGroupedProductId);
        if (parentGroupedProduct != null)
        {
            model.AssociatedToProductId = product.ParentGroupedProductId;
            model.AssociatedToProductName = parentGroupedProduct.Name;
        }

        model.LastStockQuantity = product.StockQuantity;

        model.SelectedProductTags = (await _productTagService.GetAllProductTagsByProductIdAsync(product.Id)).Select(tag => tag.Name).ToList();
        model.AvailableProductTags = (await _productTagService.GetAllProductTagsAsync())
            .Select(pt => new SelectListItem { Text = pt.Name, Value = pt.Name }).ToList();

        model.ProductAttributesExist = (await _productAttributeService.GetAllProductAttributesAsync()).Any();

        model.CanCreateCombinations = await (await _productAttributeService
            .GetProductAttributeMappingsByProductIdAsync(product.Id)).AnyAwaitAsync(async pam => (await _productAttributeService.GetProductAttributeValuesAsync(pam.Id)).Any());

        if (!excludeProperties)
        {
            model.SelectedCategoryIds = (await _categoryService.GetProductCategoriesByProductIdAsync(product.Id, true))
                .Select(productCategory => productCategory.CategoryId).ToList();
            model.SelectedManufacturerIds = (await _manufacturerService.GetProductManufacturersByProductIdAsync(product.Id, true))
                .Select(productManufacturer => productManufacturer.ManufacturerId).ToList();
        }

        //prepare copy product model
        await PrepareCopyProductModelAsync(model.CopyProductModel, product);

        //prepare nested search model
        PrepareRelatedProductSearchModel(model.RelatedProductSearchModel, product);
        PrepareCrossSellProductSearchModel(model.CrossSellProductSearchModel, product);
        PrepareFilterLevelValuesSearchModel(model.FilterLevelValueSearchModel, product);
        PrepareAssociatedProductSearchModel(model.AssociatedProductSearchModel, product);
        PrepareProductPictureSearchModel(model.ProductPictureSearchModel, product);
        PrepareProductVideoSearchModel(model.ProductVideoSearchModel, product);
        PrepareProductSpecificationAttributeSearchModel(model.ProductSpecificationAttributeSearchModel, product);
        PrepareProductOrderSearchModel(model.ProductOrderSearchModel, product);
        PrepareTierPriceSearchModel(model.TierPriceSearchModel, product);
        await PrepareStockQuantityHistorySearchModelAsync(model.StockQuantityHistorySearchModel, product);
        PrepareProductAttributeMappingSearchModel(model.ProductAttributeMappingSearchModel, product);
        PrepareProductAttributeCombinationSearchModel(model.ProductAttributeCombinationSearchModel, product);

        model.Product3dObject = await PrepareProduct3dObjectModelAsync(null, product);

        //define localized model configuration action
        localizedModelConfiguration = async (locale, languageId) =>
        {
            locale.Name = await _localizationService.GetLocalizedAsync(product, entity => entity.Name, languageId, false, false);
            locale.FullDescription = await _localizationService.GetLocalizedAsync(product, entity => entity.FullDescription, languageId, false, false);
            locale.ShortDescription = await _localizationService.GetLocalizedAsync(product, entity => entity.ShortDescription, languageId, false, false);
            locale.MetaKeywords = await _localizationService.GetLocalizedAsync(product, entity => entity.MetaKeywords, languageId, false, false);
            locale.MetaDescription = await _localizationService.GetLocalizedAsync(product, entity => entity.MetaDescription, languageId, false, false);
            locale.MetaTitle = await _localizationService.GetLocalizedAsync(product, entity => entity.MetaTitle, languageId, false, false);
            locale.SeName = await _urlRecordService.GetSeNameAsync(product, languageId, false, false);
        };
    }

    //set default values for the new model
    if (product == null)
    {
        model.MaximumCustomerEnteredPrice = 1000;
        model.MaxNumberOfDownloads = 10;
        model.RecurringCycleLength = 100;
        model.RecurringTotalCycles = 10;
        model.RentalPriceLength = 1;
        model.StockQuantity = 10000;
        model.NotifyAdminForQuantityBelow = 1;
        model.OrderMinimumQuantity = 1;
        model.OrderMaximumQuantity = 10000;
        model.TaxCategoryId = _taxSettings.DefaultTaxCategoryId;
        model.UnlimitedDownloads = true;
        model.IsShipEnabled = true;
        model.AllowCustomerReviews = true;
        model.Published = true;
        model.VisibleIndividually = true;
    }

    model.PrimaryStoreCurrencyCode = (await _currencyService.GetCurrencyByIdAsync(_currencySettings.PrimaryStoreCurrencyId)).CurrencyCode;
    model.BaseWeightIn = (await _measureService.GetMeasureWeightByIdAsync(_measureSettings.BaseWeightId)).Name;
    model.BaseDimensionIn = (await _measureService.GetMeasureDimensionByIdAsync(_measureSettings.BaseDimensionId)).Name;
    model.HasAvailableSpecificationAttributes =
        (await _specificationAttributeService.GetSpecificationAttributesWithOptionsAsync()).Any();

    var currentVendor = await _workContext.GetCurrentVendorAsync();
    model.IsLoggedInAsVendor = currentVendor != null;

    //prepare localized models
    if (!excludeProperties)
        model.Locales = await _localizedModelFactory.PrepareLocalizedModelsAsync(localizedModelConfiguration);

    //prepare editor settings
    model.ProductEditorSettingsModel = await _settingModelFactory.PrepareProductEditorSettingsModelAsync();

    //prepare available product templates
    await _baseAdminModelFactory.PrepareProductTemplatesAsync(model.AvailableProductTemplates, false);

    //prepare available product types
    var productTemplates = await _productTemplateService.GetAllProductTemplatesAsync();
    foreach (var productType in Enum.GetValues(typeof(ProductType)).OfType<ProductType>())
    {
        model.ProductsTypesSupportedByProductTemplates.Add((int)productType, new List<SelectListItem>());
        foreach (var template in productTemplates)
        {
            var list = (IList<int>)TypeDescriptor.GetConverter(typeof(List<int>)).ConvertFrom(template.IgnoredProductTypes) ?? new List<int>();
            if (string.IsNullOrEmpty(template.IgnoredProductTypes) || !list.Contains((int)productType))
            {
                model.ProductsTypesSupportedByProductTemplates[(int)productType].Add(new SelectListItem
                {
                    Text = template.Name,
                    Value = template.Id.ToString()
                });

        return RedirectToAction("Edit", "Product", new { id = productId });

    //not found
    return await List();
}

[CheckPermission(StandardPermission.Catalog.PRODUCTS_CREATE_EDIT_DELETE)]
public virtual async Task<IActionResult> Create()
{
    //validate maximum number of products per vendor
    var currentVendor = await _workContext.GetCurrentVendorAsync();
    if (_vendorSettings.MaximumProductNumber > 0 &&
        currentVendor != null &&
        await _productService.GetNumberOfProductsByVendorIdAsync(currentVendor.Id) >= _vendorSettings.MaximumProductNumber)
    {
        _notificationService.ErrorNotification(string.Format(await _localizationService.GetResourceAsync("Admin.Catalog.Products.ExceededMaximumNumber"),
            _vendorSettings.MaximumProductNumber));
        return RedirectToAction("List");
    }

    //prepare model
    var model = await _productModelFactory.PrepareProductModelAsync(new ProductModel(), null);

    return View(model);
}

[HttpPost, ParameterBasedOnFormName("save-continue", "continueEditing")]
[CheckPermission(StandardPermission.Catalog.PRODUCTS_CREATE_EDIT_DELETE)]
public virtual async Task<IActionResult> Create(ProductModel model, bool continueEditing)
{
    //validate maximum number of products per vendor
    var currentVendor = await _workContext.GetCurrentVendorAsync();
    if (_vendorSettings.MaximumProductNumber > 0 &&
        currentVendor != null &&
        await _productService.GetNumberOfProductsByVendorIdAsync(currentVendor.Id) >= _vendorSettings.MaximumProductNumber)
    {
        _notificationService.ErrorNotification(string.Format(await _localizationService.GetResourceAsync("Admin.Catalog.Products.ExceededMaximumNumber"),
            _vendorSettings.MaximumProductNumber));
        return RedirectToAction("List");
    }

    if (ModelState.IsValid)
    {
        //a vendor should have access only to his products
        if (currentVendor != null)
            model.VendorId = currentVendor.Id;

        //vendors cannot edit "Show on home page" property
        if (currentVendor != null && model.ShowOnHomepage)
            model.ShowOnHomepage = false;

        //product
        var product = model.ToEntity<Product>();
        product.CreatedOnUtc = DateTime.UtcNow;
        product.UpdatedOnUtc = DateTime.UtcNow;
        await _productService.InsertProductAsync(product);

        //search engine name
        model.SeName = await _urlRecordService.ValidateSeNameAsync(product, model.SeName, product.Name, true);
        await _urlRecordService.SaveSlugAsync(product, model.SeName, 0);

        //locales
        await UpdateLocalesAsync(product, model);

        //categories
        await SaveCategoryMappingsAsync(product, model);

        //manufacturers
        await SaveManufacturerMappingsAsync(product, model);

        //stores
        await _storeMappingService.SaveStoreMappingsAsync(product, model.SelectedStoreIds);

        //discounts
        await SaveDiscountMappingsAsync(product, model);

        //tags
        await _productTagService.UpdateProductTagsAsync(product, model.SelectedProductTags.ToArray());

        //warehouses
        await SaveProductWarehouseInventoryAsync(product, model);

        //quantity change history
        await _productService.AddStockQuantityHistoryEntryAsync(product, product.StockQuantity, product.StockQuantity, product.WarehouseId,
            await _localizationService.GetResourceAsync("Admin.StockQuantityHistory.Messages.Edit"));

        //activity log
        await _customerActivityService.InsertActivityAsync("AddNewProduct",
            string.Format(await _localizationService.GetResourceAsync("ActivityLog.AddNewProduct"), product.Name), product);

        _notificationService.SuccessNotification(await _localizationService.GetResourceAsync("Admin.Catalog.Products.Added"));

        if (!continueEditing)
            return RedirectToAction("List");

        return RedirectToAction("Edit", new { id = product.Id });
    }

    //prepare model
    model = await _productModelFactory.PrepareProductModelAsync(model, null, true);

    //if we got this far, something failed, redisplay form
    return View(model);
}

[CheckPermission(StandardPermission.Catalog.PRODUCTS_VIEW)]
public virtual async Task<IActionResult> Edit(int id)
{
    //try to get a product with the specified id
    var product = await _productService.GetProductByIdAsync(id);
    if (product == null || product.Deleted)
        return RedirectToAction("List");

    //a vendor should have access only to his products
    var currentVendor = await _workContext.GetCurrentVendorAsync();
    if (currentVendor != null && product.VendorId != currentVendor.Id)
        return RedirectToAction("List");

    //prepare model
    var model = await _productModelFactory.PrepareProductModelAsync(null, product);

    return View(model);
}

[HttpPost]
[CheckPermission(StandardPermission.Catalog.PRODUCTS_CREATE_EDIT_DELETE)]
public virtual async Task<IActionResult> PreTranslate(int itemId)
{
    var translationModel = new TranslationModel();

    //try to get a product with the specified id
    var product = await _productService.GetProductByIdAsync(itemId);
    if (product == null || product.Deleted)
        return Json(translationModel);

    //a vendor should have access only to his products
    var currentVendor = await _workContext.GetCurrentVendorAsync();
    if (currentVendor != null && product.VendorId != currentVendor.Id)
        return Json(translationModel);

    //prepare model
    var model = await _productModelFactory.PrepareProductModelAsync(null, product);

    translationModel = await _translationModelFactory.PrepareTranslationModelAsync(model,
        (nameof(ProductLocalizedModel.Name), false),
        (nameof(ProductLocalizedModel.ShortDescription), false),
        (nameof(ProductLocalizedModel.FullDescription), true));

    return Json(translationModel);
}

[HttpPost, ParameterBasedOnFormName("save-continue", "continueEditing")]
[CheckPermission(StandardPermission.Catalog.PRODUCTS_CREATE_EDIT_DELETE)]
public virtual async Task<IActionResult> Edit(ProductModel model, bool continueEditing)
{
    //try to get a product with the specified id
    var product = await _productService.GetProductByIdAsync(model.Id);
    if (product == null || product.Deleted)
        return RedirectToAction("List");

    //a vendor should have access only to his products
    var currentVendor = await _workContext.GetCurrentVendorAsync();
    if (currentVendor != null && product.VendorId != currentVendor.Id)
        return RedirectToAction("List");

    //check if the product quantity has been changed while we were editing the product
    //and if it has been changed then we show error notification
    //and redirect on the editing page without data saving
    if (product.StockQuantity != model.LastStockQuantity)
    {
        _notificationService.ErrorNotification(await _localizationService.GetResourceAsync("Admin.Catalog.Products.Fields.StockQuantity.ChangedWarning"));
        return RedirectToAction("Edit", new { id = product.Id });
    }

    if (ModelState.IsValid)
    {
        //a vendor should have access only to his products
        if (currentVendor != null)
            model.VendorId = currentVendor.Id;

        //we do not validate maximum number of products per vendor when editing existing products (only during creation of new products)
        //vendors cannot edit "Show on home page" property
        if (currentVendor != null && model.ShowOnHomepage != product.ShowOnHomepage)
            model.ShowOnHomepage = product.ShowOnHomepage;

        //some previously used values
        var prevTotalStockQuantity = await _productService.GetTotalStockQuantityAsync(product);
        var prevDownloadId = product.DownloadId;
        var prevSampleDownloadId = product.SampleDownloadId;
        var previousStockQuantity = product.StockQuantity;
        var previousWarehouseId = product.WarehouseId;
        var previousProductType = product.ProductType;
        var previousRequiredProductIds = product.RequiredProductIds;

        //product
        product = model.ToEntity(product);

        product.UpdatedOnUtc = DateTime.UtcNow;

        var requireOtherProductsError = string.Empty;

        if (product.RequireOtherProducts && !string.IsNullOrEmpty(product.RequiredProductIds))
        {
            var requiredProductIds = _productService.ParseRequiredProductIds(product);

            foreach (var requiredProduct in await _productService.GetProductsByIdsAsync(requiredProductIds.ToArray()))
            {
                if (product.Id == requiredProduct.Id || await isCyclicallyRequired(requiredProduct))
                    requireOtherProductsError = await _localizationService.GetResourceAsync("Admin.Catalog.Products.RelatedProducts.CyclicallyRelated");

                break;
            }
        }

        if (!string.IsNullOrEmpty(requireOtherProductsError))
            product.RequiredProductIds = previousRequiredProductIds;

        await _productService.UpdateProductAsync(product);

        //remove associated products
        if (previousProductType == ProductType.GroupedProduct && product.ProductType == ProductType.SimpleProduct)
        {
            var store = await _storeContext.GetCurrentStoreAsync();
            var storeId = store?.Id ?? 0;
            var vendorId = currentVendor?.Id ?? 0;

            var associatedProducts = await _productService.GetAssociatedProductsAsync(product.Id, storeId, vendorId);
            foreach (var associatedProduct in associatedProducts)
            {
                associatedProduct.ParentGroupedProductId = 0;
                await _productService.UpdateProductAsync(associatedProduct);
            }
        }

        //search engine name
        model.SeName = await _urlRecordService.ValidateSeNameAsync(product, model.SeName, product.Name, true);
        await _urlRecordService.SaveSlugAsync(product, model.SeName, 0);

        //locales
        await UpdateLocalesAsync(product, model);

        //tags
        await _productTagService.UpdateProductTagsAsync(product, model.SelectedProductTags.ToArray());

        //warehouses
        await SaveProductWarehouseInventoryAsync(product, model);

        //categories
        await SaveCategoryMappingsAsync(product, model);

        //manufacturers
        await SaveManufacturerMappingsAsync(product, model);

        //stores
        await _storeMappingService.SaveStoreMappingsAsync(product, model.SelectedStoreIds);

        //discounts
        await SaveDiscountMappingsAsync(product, model);

        //picture seo names
        await UpdatePictureSeoNamesAsync(product);

        //back in stock notifications
        if (product.ManageInventoryMethod == ManageInventoryMethod.ManageStock &&
            product.BackorderMode == BackorderMode.NoBackorders &&
            product.AllowBackInStockSubscriptions &&
            await _productService.GetTotalStockQuantityAsync(product) > 0 &&
            prevTotalStockQuantity <= 0 &&
            product.Published &&
            !product.Deleted)
        {
            await _backInStockSubscriptionService.SendNotificationsToSubscribersAsync(product);
        }

        //delete an old "download" file (if deleted or updated)
        if (prevDownloadId > 0 && prevDownloadId != product.DownloadId)
        {
            var prevDownload = await _downloadService.GetDownloadByIdAsync(prevDownloadId);
            if (prevDownload != null)
                await _downloadService.DeleteDownloadAsync(prevDownload);
        }

        //delete an old "sample download" file (if deleted or updated)
        if (prevSampleDownloadId > 0 && prevSampleDownloadId != product.SampleDownloadId)
        {
            var prevSampleDownload = await _downloadService.GetDownloadByIdAsync(prevSampleDownloadId);
            if (prevSampleDownload != null)
                await _downloadService.DeleteDownloadAsync(prevSampleDownload);
        }

        //quantity change history
        if (previousWarehouseId != product.WarehouseId)
        {
            //warehouse is changed 
            //compose a message
            var oldWarehouseMessage = string.Empty;
            if (previousWarehouseId > 0)
            {
                var oldWarehouse = await _warehouseService.GetWarehouseByIdAsync(previousWarehouseId);
                if (oldWarehouse != null)
                    oldWarehouseMessage = string.Format(await _localizationService.GetResourceAsync("Admin.StockQuantityHistory.Messages.EditWarehouse.Old"), oldWarehouse.Name);
            }

            var newWarehouseMessage = string.Empty;
            if (product.WarehouseId > 0)
            {
                var newWarehouse = await _warehouseService.GetWarehouseByIdAsync(product.WarehouseId);
                if (newWarehouse != null)
                    newWarehouseMessage = string.Format(await _localizationService.GetResourceAsync("Admin.StockQuantityHistory.Messages.EditWarehouse.New"), newWarehouse.Name);
            }

            var message = string.Format(await _localizationService.GetResourceAsync("Admin.StockQuantityHistory.Messages.EditWarehouse"), oldWarehouseMessage, newWarehouseMessage);

            //record history
            await _productService.AddStockQuantityHistoryEntryAsync(product, -previousStockQuantity, 0, previousWarehouseId, message);
            await _productService.AddStockQuantityHistoryEntryAsync(product, product.StockQuantity, product.StockQuantity, product.WarehouseId, message);
        }
        else
        {
            await _productService.AddStockQuantityHistoryEntryAsync(product, product.StockQuantity - previousStockQuantity, product.StockQuantity,
                product.WarehouseId, await _localizationService.GetResourceAsync("Admin.StockQuantityHistory.Messages.Edit"));
        }

        //activity log
        await _customerActivityService.InsertActivityAsync("EditProduct",
            string.Format(await _localizationService.GetResourceAsync("ActivityLog.EditProduct"), product.Name), product);

        if (string.IsNullOrEmpty(requireOtherProductsError))
        {
            _notificationService.SuccessNotification(await _localizationService.GetResourceAsync("Admin.Catalog.Products.Updated"));
        }
        else
        {
            _notificationService.ErrorNotification(requireOtherProductsError);

            //prepare model
            model = await _productModelFactory.PrepareProductModelAsync(model, product, true);

            return View(model);
        }

        if (!continueEditing)
            return RedirectToAction("List");

        return RedirectToAction("Edit", new { id = product.Id });
    }

    //prepare model
    model = await _productModelFactory.PrepareProductModelAsync(model, product, true);

    //if we got this far, something failed, redisplay form
    return View(model);

